async function gql(query, variables = {}) {
  const data = await fetch('https://api.hashnode.com/', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      query,
      variables,
    }),
  });

  return data.json();
}

const GET_USER_ARTICLES = `
  query GetUserArticles($page: Int!) {
      user(username: "ahammadshawki8") {
          publication {
              posts(page: $page) {
                  title
                  dateAdded
                  brief
                  slug
              }
          }
      }
  }
`;

const articles = gql(GET_USER_ARTICLES, { page: 0 })
  .then((result) => {
    Window.data = result.data.user.publication.posts;
    console.log(Window.data);
  });

